import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css']
})
export class RegisterComponent {
  name: string = '';
  email: string = '';
  password: string = '';
  studentId: string = '';
  confirmPassword: string = '';
  errorMessage: string = '';
  successMessage: string = '';
  isLoading: boolean = false;

  constructor(private authService: AuthService, private router: Router) {}

  registerUser(): void {
    if (!this.name || !this.email || !this.password || !this.studentId) {
      this.errorMessage = 'Please fill in all fields';
      return;
    }

    if (this.password !== this.confirmPassword) {
      this.errorMessage = 'Passwords do not match';
      return;
    }

    if (this.password.length < 6) {
      this.errorMessage = 'Password must be at least 6 characters long';
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';
    this.successMessage = '';

    const result = this.authService.registerUser({
      name: this.name,
      email: this.email,
      password: this.password,
      studentId: this.studentId
    });

    if (result.success) {
      this.successMessage = result.message;
      setTimeout(() => {
        this.router.navigate(['/login']);
      }, 2000);
    } else {
      this.errorMessage = result.message;
    }

    this.isLoading = false;
  }

  goToLogin(): void {
    this.router.navigate(['/login']);
  }

  validateUser(): boolean {
    return !!(this.name && this.email && this.password && this.studentId && 
           this.password === this.confirmPassword && this.password.length >= 6);
  }
}
<div class="register-container">
  <div class="register-card">
    <h2>User Registration</h2>
    <form (ngSubmit)="registerUser()">
      <div class="form-group">
        <label for="name">Full Name:</label>
        <input 
          type="text" 
          id="name" 
          name="name" 
          [(ngModel)]="name" 
          required 
          placeholder="Enter your full name"
        />
      </div>

      <div class="form-group">
        <label for="email">Email:</label>
        <input 
          type="email" 
          id="email" 
          name="email" 
          [(ngModel)]="email" 
          required 
          email
          placeholder="Enter your email"
        />
      </div>

      <div class="form-group">
        <label for="studentId">Student ID:</label>
        <input 
          type="text" 
          id="studentId" 
          name="studentId" 
          [(ngModel)]="studentId" 
          required 
          placeholder="Enter your student ID"
        />
      </div>

      <div class="form-group">
        <label for="password">Password:</label>
        <input 
          type="password" 
          id="password" 
          name="password" 
          [(ngModel)]="password" 
          required 
          minlength="6"
          placeholder="Enter your password (min 6 characters)"
        />
      </div>

      <div class="form-group">
        <label for="confirmPassword">Confirm Password:</label>
        <input 
          type="password" 
          id="confirmPassword" 
          name="confirmPassword" 
          [(ngModel)]="confirmPassword" 
          required 
          placeholder="Confirm your password"
        />
      </div>

      <div class="error-message" *ngIf="errorMessage">
        {{ errorMessage }}
      </div>

      <div class="success-message" *ngIf="successMessage">
        {{ successMessage }}
      </div>

      <button type="submit" class="register-btn" [disabled]="isLoading || !validateUser()">
        <span *ngIf="!isLoading">Register</span>
        <span *ngIf="isLoading">Registering...</span>
      </button>
    </form>

    <div class="register-links">
      <p>Already have an account? <a (click)="goToLogin()">Login here</a></p>
    </div>
  </div>
</div>
